```class Solution {
public:
    bool checkRecord(string s) {
        int absent = 0, late = 0;
        for (char c : s) {
            if (c == 'A') absent++;
            if (c == 'L') late = late == 2 ? 2 : late + 1;
            else late = 0;
            if (absent >= 2 || late == 3) return false;
        }
        return true;
    }
};
